// 1. Function declaration — hoisted (works before declaration in file)
function greet1(name) {
  return `Hello, ${name}!`;
}

// 2. Function expression — NOT hoisted
const greet2 = function(name) {
  return `Hello, ${name}!`;
};

// 3. Arrow function — short, modern, no own 'this'
const greet3 = name => `Hello, ${name}!`;

console.log(greet1("Alice"));
console.log(greet2("Bob"));
console.log(greet3("Carol"));

instruction:
Arrow functions have shortcuts based on how much they do:

```js
// Multiple statements:
const fn = (a, b) => { return a + b; };

// Single expression (implicit return):
const fn = (a, b) => a + b;

// Single parameter (no parens needed):
const fn = n => n * 2;

// No parameters:
const fn = () => "hello";
```

